"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { particleStore } from "@/lib/particleStore";

gsap.registerPlugin(ScrollTrigger);

/**
 * Scroll layout: #scroll-root = 500vh, window max scroll = 400vh
 *
 *   Scroll   Progress   Section
 *   ───────  ─────────  ─────────────────────────
 *     0 vh     0.000    Hero (section-1 at top:0)
 *   100 vh     0.250    [disintegration zone]
 *   200 vh     0.500    Mục đích (section-2 at top:200vh)
 *   300 vh     0.750    Core values (section-3 at top:300vh)
 *   400 vh     1.000    Gallery (section-4 at top:400vh)
 *
 * Snap anchor points: 0, 0.5, 0.75, 1.0
 *
 * Particle phase map (progress 0 → 1):
 *   0.00 – 0.10   introProgress
 *   0.08 – 0.42   scrollProgress  (disintegration)
 *   0.42 – 0.50   assemblyProgress (sphere forms)
 *   0.62 – 0.75   splitProgress   (4 mini-circles)
 */
export default function ScrollController() {
  const heroTitleRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    heroTitleRef.current =
      document.querySelector<HTMLElement>("[data-hero-title]");

    const ctx = gsap.context(() => {
      ScrollTrigger.create({
        trigger: "#scroll-root",
        start: "top top",
        end: "bottom bottom",
        scrub: 1.0,

        // ── Snap to section anchor points ─────────────────────────────────
        // Hero(0) | Mục đích(0.5) | Core values(0.75) | Gallery(1.0)
        snap: {
          snapTo: [0, 0.5, 0.75, 1.0],
          duration: { min: 0.35, max: 0.75 },
          delay: 0.08,
          ease: "power2.inOut",
          inertia: false,
        },

        onUpdate: (self) => {
          const p = self.progress;

          // ── Hero title fade ──────────────────────────────────────────────
          if (heroTitleRef.current) {
            heroTitleRef.current.style.opacity =
              String(Math.max(0, 1 - p / 0.09));
          }

          // ── Intro ────────────────────────────────────────────────────────
          particleStore.introProgress =
            Math.min(1, Math.max(0, p / 0.10));

          // ── Phases (tuned for max-scroll=400vh, progress 0→1) ─────────
          const DIS_S = 0.08, DIS_E = 0.42;
          const ASM_S = 0.42, ASM_E = 0.50;
          const SPL_S = 0.62, SPL_E = 0.75;

          if (p < DIS_S) {
            particleStore.scrollProgress   = 0;
            particleStore.assemblyProgress = 0;
            particleStore.splitProgress    = 0;
          } else if (p <= DIS_E) {
            particleStore.scrollProgress   = (p - DIS_S) / (DIS_E - DIS_S);
            particleStore.assemblyProgress = 0;
            particleStore.splitProgress    = 0;
          } else if (p < ASM_S) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 0;
            particleStore.splitProgress    = 0;
          } else if (p <= ASM_E) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = (p - ASM_S) / (ASM_E - ASM_S);
            particleStore.splitProgress    = 0;
          } else if (p < SPL_S) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 1;
            particleStore.splitProgress    = 0;
          } else if (p <= SPL_E) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 1;
            particleStore.splitProgress    = (p - SPL_S) / (SPL_E - SPL_S);
          } else {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 1;
            particleStore.splitProgress    = 1;
          }
        },
      });
    });

    return () => ctx.revert();
  }, []);

  return null;
}
